/**
 * Simple File Upload Test - Debugging hanging/timeout issues
 */

import React from 'react';
import { render, screen } from '@testing-library/react';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { describe, it, expect, beforeEach, jest } from '@jest/globals';
import '@testing-library/jest-dom';

// Create a simple test component for file upload testing
const SimpleFileUploadForm = () => {
  return (
    <div data-testid="simple-file-upload">
      <input type="file" data-testid="file-input" />
      <div data-testid="file-status">No files selected</div>
      <button data-testid="upload-button">Upload</button>
    </div>
  );
};

describe('Simple File Upload Test', () => {
  let queryClient: QueryClient;

  beforeEach(() => {
    queryClient = new QueryClient({
      defaultOptions: {
        queries: { retry: false },
        mutations: { retry: false },
      },
    });
    jest.clearAllMocks();
  });

  it('should render file upload form', () => {
    render(
      <QueryClientProvider client={queryClient}>
        <SimpleFileUploadForm />
      </QueryClientProvider>
    );

    expect(screen.getByTestId('simple-file-upload')).toBeInTheDocument();
    expect(screen.getByTestId('file-input')).toBeInTheDocument();
    expect(screen.getByTestId('upload-button')).toBeInTheDocument();
  });

  it('should display initial status', () => {
    render(
      <QueryClientProvider client={queryClient}>
        <SimpleFileUploadForm />
      </QueryClientProvider>
    );

    expect(screen.getByTestId('file-status')).toHaveTextContent('No files selected');
  });

  it('should handle file input interaction', () => {
    render(
      <QueryClientProvider client={queryClient}>
        <SimpleFileUploadForm />
      </QueryClientProvider>
    );

    const fileInput = screen.getByTestId('file-input');
    expect(fileInput).toBeInTheDocument();
    expect(fileInput).toHaveAttribute('type', 'file');
  });
});